	}
	return s.ExecuteBeadLoopStore.Claim(id, assignee)
}

func (s *cleanupAdvanceClaimStore) ClaimWithOptions(id, assignee, session, worktree string) error {
	claim := atomic.AddInt32(s.claimCalls, 1)
	if claim == 1 {
