		SessionID:    "sess-watch-transient-predispatch",
		WorkerID:     "worker-watch-transient-predispatch",
	})

	// ToolCallTimeout is a per-tool-call sanity cap: if a single tool_call
	// event has no matching tool_result within this window, the drain cancels
	// the execution. This is NOT for loop detection (see loopDetector in
	// agent_runner_service.go) — it catches individually hung subprocesses
	// (e.g., network deadlock in git push) that would otherwise absorb
	// unlimited wall-clock without surfacing.
	//
	// INTERIM (FEAT-004 D1d): raised from 30m to 90m. A bare TUI can run a
	// long build/test tool (or a slow/stalled model turn) and succeed; the 30m
	// cap was cancelling healthy long attempts and losing completed work.
	// Until D1d makes this a per-tool config seam, 90m keeps the hung-subprocess
	// catch while not being tighter than a real build/test.
	ToolCallTimeout = 5400000 // 90 minutes
	DefaultLogDir   = ".ddx/agent-logs"
)

// ResolveLogDir returns an absolute session-log directory path anchored at
// projectRoot. Callers that construct an agent.Runner must use this to avoid
// the Runner's relative DefaultLogDir resolving against process CWD — which
// historically wrote logs to stray locations like cli/internal/server/.ddx/.
func ResolveLogDir(projectRoot, configured string) string {
	if configured == "" {
		configured = DefaultLogDir
	}
	if filepath.IsAbs(configured) {
		return configured
	}
	if projectRoot == "" {
		return configured
	}
	clean := filepath.Clean(filepath.FromSlash(configured))
	prefix := ddxroot.DirName + string(filepath.Separator)
	if clean == DefaultLogDir || clean == ddxroot.DirName || clean == "."+string(filepath.Separator)+ddxroot.DirName || clean == ".ddx" || clean == filepath.Clean(DefaultLogDir) || strings.HasPrefix(clean, prefix) {
		return projectStatePath(projectRoot, configured)
	}
	return filepath.Join(projectRoot, configured)
}

package agent

import (
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

func projectStatePath(projectRoot, rel string) string {
	if projectRoot == "" || rel == "" {
		return filepath.Join(projectRoot, rel)
	}

	clean := filepath.Clean(filepath.FromSlash(rel))
	if clean == ddxroot.DirName {
		return ddxroot.JoinProject(projectRoot)
	}

	prefix := ddxroot.DirName + string(filepath.Separator)
	if strings.HasPrefix(clean, prefix) {
		trimmed := strings.TrimPrefix(clean, prefix)
		if trimmed == "" || trimmed == "." {
			return ddxroot.JoinProject(projectRoot)
		}
		return ddxroot.JoinProject(projectRoot, strings.Split(trimmed, string(filepath.Separator))...)
	}

	return filepath.Join(projectRoot, clean)
}

func executeBeadArtifactRoot(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, "executions")
}

